import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.line.biz/en/reference/messaging-api/";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from LINE Messaging API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:line",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const lineFirewall = {",
    '  name: "line",',
    '  description: "LINE Messaging API",',
    "  placeholders: {",
    `    LINE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.line.me",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.LINE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating LINE firewall config...");
  const ts = generateTypeScript();
  writeOutput("line", ts, import.meta.dirname);
}
